qry:select.qry:xquery:
for $r in SQL(' SELECT DPER.d_calle, DPER.e_numero, DPER.d_piso, DPER.d_departamento, LOC.d_localidad, PRO.c_provincia, LOC.c_postal FROM PER01_DOMIC_PER as DPER, ORG19_LOCALIDADES as LOC, ORG35_PROVINCIAS as PRO JOIN DPER.oi_localidad INNER LOC.oi_localidad, LOC.oi_provincia INNER PRO.oi_provincia
WHERE DPER.l_domic_fiscal = 1 AND DPER.oi_personal = {%= #SOURCE:@oi_personal %}
')/ROWS/ROW
